const OLD_PREFIXES=["tp65","tp64","tp63","tp62","tp61","tp60","tp59","tp58","tp57","tp56","tp55","tp54","tp53","tp52","tp51","tp50","tp49","tp48","tp47","tp46","tp45","tp44","tp43","tp42","tp41","tp40","tp39","tp38","tp37","tp36","tp35","tp34","tp33","tp32","tp31","tp30"];
const ldWithMigration=async(newKey,oldSuffix)=>{
  // Try new fixed key first
  const v=await ld(newKey);
  if(v!==null)return v;
  // Try old versioned keys in order (newest first)
  for(const prefix of OLD_PREFIXES){
    const old=await ld(prefix+":"+oldSuffix);
    if(old!==null){
      // Migrate to new key
      try{await window.storage.set(newKey,JSON.stringify(old));}catch(e){}
      return old;
    }
  }
  return null;
};
