// Normalize any location string to its canonical form
// RULE: Airports/terminals always normalize.
// Full addresses (hotel + street + number) are kept as-is.
// Only bare location names (no comma, no street number) get replaced with CABA.
const normLoc=t=>{
  if(!t||!t.trim())return t;
  const s=t.trim();const u=s.toLowerCase();
  if(/aeroparque|newbery|\baep\b|jorge newbery/i.test(u)) return "Aeroparque Jorge Newbery (AEP)";
  if(/ezeiza|pistarini|\beze\b|aeropuerto.*buenos aires|aeropuerto internacional/i.test(u)) return "Aeropuerto Ezeiza Ministro Pistarini (EZE)";
  if(/colonia express|\bclx\b/i.test(u)) return "Colonia Express (CLX)";
  if(/buque bus|\bbqb\b/i.test(u)) return "Buque Bus (BQB)";
  if(/quinquela|\bpqm\b/i.test(u)) return "Terminal Cruceros Quinquela Martín (PQM)";
  const hasNum=/\b\d{3,}\b/.test(s);
  const strippedCountry=s.replace(/,?\s*(argentina|ar|arg|buenos aires)\s*$/i,'').trim();
  const hasAddrComma=strippedCountry.includes(',');
  const isRealAddr=hasNum||hasAddrComma;
  if(!isRealAddr){if(/\bcaba\b|ciudad\s+aut[oó]noma|ciudad\s+de\s+buenos\s+aires|^buenos\s+aires$|^b\.?a\.?$|^centro$|^microcentro$|^palermo$|^recoleta$|^belgrano$|^san\s+telmo$|^puerto\s+madero$|^retiro$|^congreso$|^once$|^balvanera$|^almagro$|^boedo$|^flores$|^caballito$|^chacarita$|^colegiales$|^nu[nñ]ez$|^villa\s+crespo$|^villa\s+urquiza$|^monserrat$|^tribunales$/i.test(u))return "Ciudad Autónoma de Buenos Aires (CABA)";}
  if(/^buenos\s+aires,?\s*(argentina|ar|arg)?$/i.test(u)) return "Ciudad Autónoma de Buenos Aires (CABA)";
  if(/^ciudad\s+(aut[oó]noma\s+de\s+|de\s+)buenos\s+aires,?\s*(argentina|ar|arg)?$/i.test(u)) return "Ciudad Autónoma de Buenos Aires (CABA)";
  return s;
};// Extract route key (AEP/EZE/CABA/etc) from any location string
const dLoc2=t=>{
  if(!t)return null;
  const u=t.toLowerCase();
  if(/aeroparque|newbery|\baep\b/.test(u)) return "AEP";
  if(/ezeiza|pistarini|\beze\b|aeropuerto de ezeiza|aeropuerto ministro|aeropuerto internacional/.test(u)) return "EZE";
  if(/colonia express|\bclx\b/.test(u)) return "CLX";
  if(/buque bus|\bbqb\b/.test(u)) return "BQB";
  if(/quinquela|\bpqm\b/.test(u)) return "PQM";
  if(/buenos air|\bcaba\b|ciudad aut[oó]noma|microcentro|\bcentro\b|palermo|recoleta|belgrano|san telmo|puerto madero|caballito|flores|villa crespo|chacarita|colegiales|nu[nñ]ez|boedo|almagro|monserrat|balvanera|congreso|tribunales|once|abasto|retiro|pilar|tigre|zona norte|zona sur|zona oeste|gba/.test(u)) return "CABA";
  return null;
};
