const dBal=(drv,trips,pmts)=>{const e=trips.filter(r=>PAY.includes(r.status)).reduce((s,r)=>s+(r.driverPrice||0),0);const p=pmts.filter(p=>p.driverId===drv.id).reduce((s,p)=>s+p.amount,0);return e-p;};
const mAlert=r=>`TRASLADO OFRECIDO\n\nCodigo: ${r.code}\n\nFecha: ${fD(r.date)}\nHora: ${r.time} hs\nVehiculo requerido: ${r.vehicleType}\nPax: ${r.pax}${r.isArrival&&r.flightNumber?`\nVuelo arribo: ${r.flightNumber}`:""}\n\nORIGEN: ${r.origin}\nDESTINO: ${r.destination}${r.notes?`\n${r.notes}`:""}\n\nPodés aceptar?\nACEPTO o RECHAZO\n\n🌐 También podés aceptar desde tu panel web: https://angelstt.com/app`;
const mDrv=(r,d)=>`TRASLADO CONFIRMADO\n\nCodigo: ${r.code} | Prov: ${r.providerCode}\nPasajero: ${r.passengerName}\nTel: ${r.passengerPhone}\nFecha: ${fD(r.date)} - ${r.time} hs\nPax: ${r.pax}${r.isArrival&&r.flightNumber?`\nVuelo arribo: ${r.flightNumber}\nEstado: ${flL(r.flightNumber)}`:""}\n\nORIGEN: ${r.origin}\nWaze: ${waze(r.origin)}\n\nDESTINO: ${r.destination}\nWaze: ${waze(r.destination)}${r.driverLink?`\nDriver link: ${r.driverLink}`:""}${r.notes?`\nNotas: ${r.notes}`:""}\n\nValor: $${n$(r.driverPrice)}\nBuen viaje!`;
const mPax=(r,d)=>`CONFIRMACION DE TRASLADO\n\nEstimado/a ${r.passengerName},\nSu traslado esta confirmado.\n\nCodigo: ${r.code} | Ref: ${r.providerCode}\nFecha: ${fD(r.date)} - ${r.time} hs\nOrigen: ${r.origin}\nDestino: ${r.destination}\nPasajeros: ${r.pax}${r.isArrival&&r.flightNumber?`\nVuelo arribo: ${r.flightNumber}`:""}${r.notes?`\n${r.notes}`:""}\n\nSU CHOFER:\n${d?.name}\n${d?.vehicleBrand||""} ${d?.vehicleModel||""} - ${d?.vehicleColor||""}\nPatente: ${d?.plate}\nTel: ${d?.phone}\n\nPor favor, póngase en contacto con su chofer asignado.\nGracias por elegirnos!`;
const mDoc=(d,doc,days)=>`AVISO DOCUMENTACION\n\nHola ${d.name.split(" ")[0]},\nTu ${doc} vence en ${days} dia${days===1?"":"s"}.\n\nActualiza el documento para seguir recibiendo servicios.\nGracias!`;
const mReview=(d,r)=>`En ANGELS queremos saber tu opinión. Publica una reseña en nuestro perfil.\nhttps://g.page/r/CXfmb4SyGVy1EA0/review\nPor favor no olviden calificar el traslado que las realicé en Buenos Aires 😁 y colocar mi nombre en la reseña\n¡¡Muchísimas gracias!!`;

const mReport=(d,trips,from,to)=>{const lines=trips.map(r=>`${fD(r.date)} ${r.time}hs | ${r.code} | ${r.vehicleType} | ${(r.origin||"").slice(0,18)} > ${(r.destination||"").slice(0,18)} | $${n$(r.driverPrice)} | ${SM[r.status]?.l||r.status}`).join("\n");const c=trips.filter(r=>PAY.includes(r.status)).reduce((s,r)=>s+(r.driverPrice||0),0);const pe=trips.filter(r=>!FIN.includes(r.status)).reduce((s,r)=>s+(r.driverPrice||0),0);return `RESUMEN DE SERVICIOS\n${d.name}\nPeriodo: ${fD(from)} al ${fD(to)}\n\n${lines||"Sin servicios"}\n\nCompletados/Pagados: $${n$(c)}\nPendientes: $${n$(pe)}\nTOTAL: $${n$(c+pe)}`;};
const PROV_PAY=["completed","cancelled_pay","noshow"];
const provBilled=(trips)=>trips.filter(r=>PROV_PAY.includes(r.status)).reduce((s,r)=>s+(r.price||0),0);
const mProvReport=(pv,trips,from,to,collected)=>{const lines=trips.map(r=>{const bills=PROV_PAY.includes(r.status);return`${fD(r.date)} ${r.time}hs | ${r.code} | ${r.vehicleType} | ${(r.origin||"").slice(0,15)} > ${(r.destination||"").slice(0,15)} | ${bills?"$"+n$(r.price):"$0"} | ${SM[r.status]?.l||r.status}`;}).join("\n");const total=provBilled(trips);return `RESUMEN DE CUENTA\n${pv.name} (${pv.code})\nPeriodo: ${fD(from)} al ${fD(to)}\n\n${lines||"Sin reservas"}\n\nFacturado (periodo): $${n$(total)}\nCobrado (total): $${n$(collected||0)}\nSaldo pendiente: $${n$(total-(collected||0))}`;};
// Roles: admin=all, colaborador=no financial, driver=own trips
const canSee=(role,section)=>{if(role==="admin")return true;if(role==="colaborador")return!["bil","providers_finance"].includes(section);if(role==="driver")return["my_trips","my_wallet","my_profile"].includes(section);return false;};
