const css=`
@import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@400;500&display=swap');
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{--bg:#0A0C10;--s1:#111318;--s2:#181C24;--b1:rgba(255,255,255,.07);--b2:rgba(255,255,255,.13);--ac:#00D4FF;--gr:#10B981;--am:#F59E0B;--re:#EF4444;--bl:#3B82F6;--pk:#EC4899;--tx:#F0F2F5;--mu:#6B7280;--mu2:#9CA3AF;--fh:'Syne',sans-serif;--fb:'DM Sans',sans-serif;--r:12px;--rl:16px}
body{background:var(--bg);color:var(--tx);font-family:var(--fb);min-height:100vh}
.app{display:flex;height:100vh;overflow:hidden}
.sb{width:210px;min-width:210px;background:var(--s1);border-right:1px solid var(--b1);display:flex;flex-direction:column;padding:18px 10px;gap:3px;overflow-y:auto}
.logo{font-family:var(--fh);font-size:14px;font-weight:800;color:var(--ac);padding:6px 10px 18px;line-height:1.3}.logo span{color:var(--tx)}.logo small{font-size:9px;font-weight:600;letter-spacing:.5px;opacity:.6;display:block;margin-top:1px}
.ni{display:flex;align-items:center;gap:9px;padding:9px 10px;border-radius:8px;font-size:12.5px;font-weight:500;color:var(--mu2);cursor:pointer;transition:all .15s;border:none;background:none;width:100%;text-align:left}
.ni:hover{color:var(--tx);background:var(--s2)}.ni.on{color:var(--ac);background:rgba(0,212,255,.08)}
.dv{height:1px;background:var(--b1);margin:6px 0}
.ni-sec{font-size:9.5px;color:var(--mu);text-transform:uppercase;letter-spacing:.8px;padding:8px 10px 4px;font-weight:600}
.mn{flex:1;display:flex;flex-direction:column;overflow:hidden}
.tb{height:56px;display:flex;align-items:center;justify-content:space-between;padding:0 22px;border-bottom:1px solid var(--b1);background:var(--s1);flex-shrink:0}
.tt{font-family:var(--fh);font-size:15px;font-weight:700}
.cnt{flex:1;overflow-y:auto;padding:22px}
.sts{display:grid;grid-template-columns:repeat(4,1fr);gap:11px;margin-bottom:18px}
.sc{background:var(--s1);border:1px solid var(--b1);border-radius:var(--rl);padding:14px 16px}
.sl{font-size:10.5px;color:var(--mu);text-transform:uppercase;letter-spacing:.6px;margin-bottom:4px}
.sv{font-family:var(--fh);font-size:22px;font-weight:800}
.ssub{font-size:9.5px;color:var(--mu);margin-top:3px}
.ab{display:flex;align-items:center;gap:9px;background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.3);border-radius:var(--r);padding:10px 13px;margin-bottom:11px;font-size:12.5px;color:var(--re);cursor:pointer}
.ab:hover{background:rgba(239,68,68,.16)}
.abd{background:var(--re);color:#fff;font-size:9.5px;font-weight:800;padding:2px 7px;border-radius:20px;margin-left:auto}
.da{display:flex;align-items:center;gap:9px;background:rgba(245,158,11,.1);border:1px solid rgba(245,158,11,.3);border-radius:var(--r);padding:9px 13px;margin-bottom:7px;font-size:12px;color:var(--am)}
.flt{display:flex;gap:6px;align-items:center;margin-bottom:9px;flex-wrap:wrap}
.fi{background:var(--s1);border:1px solid var(--b2);color:var(--tx);border-radius:8px;padding:7px 10px;font-size:12px;font-family:var(--fb);outline:none;transition:border-color .15s}.fi:focus{border-color:var(--ac)}
.fs{background:var(--s1);border:1px solid var(--b2);color:var(--mu2);border-radius:8px;padding:7px 10px;font-size:12px;font-family:var(--fb);cursor:pointer;outline:none}.fs option{background:#1a1e28}
.btn{display:inline-flex;align-items:center;gap:5px;padding:7px 13px;border-radius:8px;border:none;font-size:12px;font-weight:500;font-family:var(--fb);cursor:pointer;transition:all .15s;white-space:nowrap;text-decoration:none}
.bp{background:var(--ac);color:#000}.bp:hover{background:#00b8d9}
.bg2{background:transparent;color:var(--mu2);border:1px solid var(--b2)}.bg2:hover{color:var(--tx);background:var(--s2)}
.bgr{background:rgba(16,185,129,.15);color:var(--gr);border:1px solid rgba(16,185,129,.3)}.bgr:hover{background:rgba(16,185,129,.25)}
.bam{background:rgba(245,158,11,.12);color:var(--am);border:1px solid rgba(245,158,11,.3)}
.bre{background:rgba(239,68,68,.12);color:var(--re);border:1px solid rgba(239,68,68,.3)}.bre:hover{background:rgba(239,68,68,.22)}
.bbl{background:rgba(59,130,246,.15);color:var(--bl);border:1px solid rgba(59,130,246,.3)}
.bpk{background:rgba(236,72,153,.12);color:var(--pk);border:1px solid rgba(236,72,153,.3)}
.sm{padding:5px 8px;font-size:11px}
.btn:disabled{opacity:.4;cursor:not-allowed}
.tw{background:var(--s1);border:1px solid var(--b1);border-radius:var(--rl);overflow:hidden}
table{width:100%;border-collapse:collapse}
thead tr{background:var(--s2)}
th{padding:9px 13px;text-align:left;font-size:10px;color:var(--mu);text-transform:uppercase;letter-spacing:.6px;font-weight:600;white-space:nowrap}
td{padding:9px 13px;font-size:12.5px;border-top:1px solid var(--b1);vertical-align:middle}
tbody tr{transition:background .1s}tbody tr:hover{background:rgba(255,255,255,.025)}
tbody tr.ug{background:rgba(239,68,68,.04)}tbody tr.fin{opacity:.55}
.badge{display:inline-flex;align-items:center;gap:4px;padding:2px 7px;border-radius:20px;font-size:10.5px;font-weight:600}
.bd{width:5px;height:5px;border-radius:50%;flex-shrink:0}
.av{border-radius:50%;display:flex;align-items:center;justify-content:center;font-family:var(--fh);font-weight:800;flex-shrink:0}
.mo{position:fixed;inset:0;background:rgba(0,0,0,.75);display:flex;align-items:center;justify-content:center;z-index:1000;padding:20px;backdrop-filter:blur(4px);animation:fi .15s ease}
@keyframes fi{from{opacity:0}to{opacity:1}}
.mc{background:var(--s1);border:1px solid var(--b2);border-radius:var(--rl);width:100%;max-width:620px;max-height:90vh;overflow-y:auto;animation:su .2s ease}
.mlg{max-width:820px}
@keyframes su{from{transform:translateY(14px);opacity:0}to{transform:translateY(0);opacity:1}}
.mh{padding:16px 20px 13px;border-bottom:1px solid var(--b1);display:flex;align-items:center;justify-content:space-between;flex-shrink:0}
.mt{font-family:var(--fh);font-size:14.5px;font-weight:700}
.mb{padding:16px 20px}
.mf{padding:13px 20px;border-top:1px solid var(--b1);display:flex;gap:6px;justify-content:flex-end;flex-wrap:wrap}
.fg{display:grid;grid-template-columns:1fr 1fr;gap:11px}
.fp{display:flex;flex-direction:column;gap:5px}
.fp.full{grid-column:1/-1}
label{font-size:11px;color:var(--mu2);font-weight:500}
input,select,textarea{background:var(--s2);border:1px solid var(--b2);color:var(--tx);border-radius:8px;padding:7px 10px;font-size:13px;font-family:var(--fb);outline:none;transition:border-color .15s}
input:focus,select:focus,textarea:focus{border-color:var(--ac)}
select option{background:#1a1e28}
textarea{resize:vertical;min-height:65px}
.dr{display:flex;justify-content:space-between;align-items:flex-start;padding:8px 0;border-bottom:1px solid var(--b1);font-size:13px}
.dr:last-child{border-bottom:none}
.dk{color:var(--mu2);font-size:11px;flex-shrink:0;margin-right:9px}
.dv2{font-weight:500;text-align:right;max-width:65%}
.tabs{display:flex;gap:3px;background:var(--s2);border-radius:9px;padding:3px;margin-bottom:16px;flex-wrap:wrap}
.tab{flex:1;min-width:60px;padding:6px 7px;text-align:center;font-size:11px;font-weight:500;border-radius:7px;cursor:pointer;color:var(--mu2);border:none;background:none;font-family:var(--fb);transition:all .15s}
.tab.on{background:var(--s1);color:var(--tx)}
.dcg{display:grid;grid-template-columns:repeat(3,1fr);gap:9px}
.dcc{background:var(--s2);border:2px solid var(--b1);border-radius:var(--r);padding:10px;cursor:pointer;transition:all .15s}
.dcc:hover{border-color:var(--ac)}.dcc.sel{border-color:var(--ac);background:rgba(0,212,255,.08)}
.dcc.inc{opacity:.3;cursor:not-allowed;border-color:rgba(239,68,68,.3)}
.rat{display:flex;align-items:center;gap:3px;font-size:10.5px;color:var(--am);font-weight:600}
.uz{border:2px dashed var(--b2);border-radius:8px;padding:13px;text-align:center;cursor:pointer;transition:all .15s;background:var(--s2);font-size:12px;color:var(--mu2)}
.uz:hover{border-color:var(--ac)}.uz.hf{border-color:var(--gr);color:var(--gr);background:rgba(16,185,129,.05)}
.uz input[type=file]{display:none}
.tg{position:relative;width:36px;height:20px}
.tg input{opacity:0;width:0;height:0}
.tgs{position:absolute;inset:0;background:var(--s2);border:1px solid var(--b2);border-radius:20px;cursor:pointer;transition:.2s}
.tgs:before{content:'';position:absolute;width:14px;height:14px;background:var(--mu);border-radius:50%;top:2px;left:2px;transition:.2s}
.tg input:checked+.tgs{background:rgba(16,185,129,.2);border-color:var(--gr)}
.tg input:checked+.tgs:before{transform:translateX(16px);background:var(--gr)}
.lw{display:flex;align-items:center;gap:7px;background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.3);border-radius:7px;padding:8px 11px;font-size:12px;color:var(--re);grid-column:1/-1}
.pw2{background:rgba(245,158,11,.1);border:1px solid rgba(245,158,11,.3);border-radius:7px;padding:8px 11px;font-size:12px;color:var(--am);grid-column:1/-1}
.wp{background:#1a2a1e;border:1px solid rgba(16,185,129,.25);border-radius:var(--r);padding:11px;font-size:11.5px;line-height:1.7;color:#d1fae5;white-space:pre-wrap;font-family:monospace;max-height:260px;overflow-y:auto}
.toast{position:fixed;bottom:20px;right:20px;background:var(--s2);border:1px solid var(--b2);border-radius:var(--r);padding:10px 15px;font-size:12.5px;color:var(--tx);z-index:9999;animation:su .2s ease;display:flex;align-items:center;gap:8px;box-shadow:0 8px 32px rgba(0,0,0,.4)}
.nd{width:6px;height:6px;border-radius:50%;background:var(--re);margin-left:auto;flex-shrink:0}
.spin{width:16px;height:16px;border:2px solid rgba(0,212,255,.3);border-top-color:var(--ac);border-radius:50%;animation:sp .6s linear infinite}
@keyframes sp{to{transform:rotate(360deg)}}
.empty{text-align:center;padding:32px 20px;color:var(--mu);font-size:12.5px}
.wcard{background:linear-gradient(135deg,rgba(0,212,255,.12),rgba(124,58,255,.12));border:1px solid rgba(0,212,255,.25);border-radius:var(--rl);padding:20px;margin-bottom:16px}
.wbal{font-family:var(--fh);font-size:30px;font-weight:800;color:var(--ac)}
.lw2{min-height:100vh;display:flex;align-items:center;justify-content:center;background:var(--bg);padding:20px}
.lc{background:var(--s1);border:1px solid var(--b2);border-radius:var(--rl);padding:32px;width:100%;max-width:400px}
.ll{font-family:var(--fh);font-size:19px;font-weight:800;color:var(--ac);margin-bottom:4px}
.ls{font-size:12px;color:var(--mu2);margin-bottom:24px}
.por{min-height:100vh;background:var(--bg);display:flex;flex-direction:column}
.ph{background:var(--s1);border-bottom:1px solid var(--b1);padding:0 18px;height:54px;display:flex;align-items:center;justify-content:space-between}
.pc{flex:1;padding:16px;max-width:800px;margin:0 auto;width:100%}
.chip{font-family:monospace;font-size:11px;background:rgba(0,212,255,.1);color:var(--ac);padding:2px 6px;border-radius:5px;letter-spacing:.4px;border:1px solid rgba(0,212,255,.2)}
.pw{position:relative}.pw input{width:100%;padding-right:36px}
.pe{position:absolute;right:9px;top:50%;transform:translateY(-50%);cursor:pointer;color:var(--mu2);background:none;border:none;padding:0}.pe:hover{color:var(--tx)}
.sb3{height:3px;border-radius:2px;transition:background .2s}
.dz{border:3px dashed var(--b2);border-radius:var(--rl);padding:30px;text-align:center;cursor:pointer;transition:all .2s;background:var(--s2)}
.dz:hover{border-color:var(--ac);background:rgba(0,212,255,.04)}
.dz input{display:none}
.vb{font-size:10px;font-weight:700;padding:2px 5px;border-radius:4px;font-family:var(--fh);letter-spacing:.4px}
.sbox{background:var(--s2);border-radius:var(--r);padding:16px;font-family:monospace;font-size:11.5px;color:var(--tx);white-space:pre-wrap;max-height:360px;overflow-y:auto;line-height:1.7;border:1px solid var(--b1)}
.rtag{font-size:10px;background:rgba(0,212,255,.1);color:var(--ac);border:1px solid rgba(0,212,255,.2);border-radius:4px;padding:1px 6px;font-family:var(--fh);font-weight:700}
@media(max-width:768px){.sb{display:none}.sts{grid-template-columns:1fr 1fr}.dcg{grid-template-columns:1fr}.fg{grid-template-columns:1fr}.mlg{max-width:100%}}
`;
// ── SHARED COMPONENTS ──────────────────────────────────────────────────────────
const Av=({id,text,size=28,fs=10})=><div className="av" style={{width:size,height:size,fontSize:fs,background:avc(id)}}>{text}</div>;
const Bdg=({status})=>{const m=SM[status]||SM.pending;return <span className="badge" style={{color:m.c,background:m.b}}><span className="bd" style={{background:m.c}}/>{m.l}</span>;};
const DR=({k,v})=><div className="dr"><div className="dk">{k}</div><div className="dv2">{v}</div></div>;
const VB=({type})=>{const c={SPRINTER:"#7C3AFF",HIACE:"#00D4FF",VAN:"#10B981",SEDAN:"#F59E0B"}[type]||"#6B7280";return <span className="vb" style={{background:`${c}22`,color:c,border:`1px solid ${c}44`}}>{type} <span style={{opacity:.7,fontWeight:400}}>{VCAP[type]||""}</span></span>;};